// // This module toggles the output on every rising edge of the clock when reset is low.
module reset_controller (
    input wire clk,
    input wire rst,
    output reg out
);

always @(posedge clk or posedge rst) begin
    if (rst) begin
        out <= 0;
    end else begin
        out <= ~out;
    end
end

endmodule
